export type DaemonConnectionPayload = {
	baseUrl: string,
	wsUrl: string,
	token: string,
};

/**  失败原因。i18n key 命名约定:`delivery.failureReason.<variant 小驼峰>`。 */
export type DeliveryFailureReasonDto = "offline" | "localPolicy" | "peerRejected" | "io" | "internal";

/**
 *  暴露给 webview 的设备和应用元数据，用于补齐前端 Sentry scope。
 * 
 *  字段命名与后端 `ScopeContext` 一一对应（`device.id` / `device.role` /
 *  `device.platform` / `app.version` / `app.channel`）。webview 侧的
 *  `device.role` 默认仍是 `webview`，这里返回的 `device_role` 是 *Rust 主进程*
 *  的角色（`gui-host`），webview 把它打到 `device.host_role` 二级 tag 上,
 *  便于 Sentry 上同时看到两端。
 */
export type DeviceMeta = {
	deviceId: string,
	deviceRole: string,
	platform: string,
	appVersion: string,
	appChannel: string,
};

/**
 *  Events emitted during update download.
 * 
 *  Carried both via the broadcast `UPDATE_PROGRESS_EVENT` (background
 *  download) and via the per-invocation `Channel<DownloadEvent>` passed to
 *  `install_update` (legacy combined download+install path).
 */
export type DownloadEvent = { event: "Started"; data: {
	contentLength: number | null,
} } | { event: "Progress"; data: {
	chunkLength: number,
} } | { event: "Finished" } | { event: "Failed"; data: {
	error: string,
} };

/**
 *  Coarse-grained phase used by `get_download_progress` so a frontend that
 *  mounts mid-download can render the right icon variant.
 */
export type DownloadPhase = "idle" | "available" | "downloading" | "ready";

/**
 *  Snapshot of current download state, queryable from the frontend so a
 *  just-mounted listener can sync up before attaching to the event stream.
 */
export type DownloadProgressSnapshot = {
	phase: DownloadPhase,
	downloaded: number,
	total: number | null,
	version: string | null,
};

/**  状态枚举:`tag` + `reason` 形式,便于前端区分四档与失败子分类。 */
export type EntryDeliveryStatusDto = { tag: "pending" } | { tag: "delivered" } | { tag: "duplicate" } | { tag: "failed"; reason: DeliveryFailureReasonDto };

export type EntryDeliveryTargetDto = {
	targetDeviceId: string,
	/**
	 *  取自空间成员目录中的人类可读名;不命中时为 `null`,前端 fallback
	 *  到 `targetDeviceId` 截断。
	 */
	targetDeviceName: string | null,
	status: EntryDeliveryStatusDto,
	/**  失败时的 wire 层错误细节,供 UI tooltip / 详情展开使用。 */
	reasonDetail: string | null,
	/**
	 *  `Pending` 时为 `None`(从未尝试过)。`#[specta(type = ...)]` 告诉 specta
	 *  这是个 ms 精度的 epoch,实际值不会超过 JS Number 安全整数范围 (~285 万年),
	 *  用 `Number<i64>` 包装绕过 BigInt 禁用规则,与 mobile_sync.rs 的 `last_seen_at_ms`
	 *  同源。
	 */
	updatedAtMs: number | null,
};

