{ tag: "historical" };

/**
 *  前端可 `error.code` switch 的 typed 错误。序列化形态:
 *  `{"code": "KEY_MATERIAL_WIPE_FAILED", "message": "..."}` 等。
 */
export type FactoryResetCommandError = 
/**
 *  space_setup facade 尚未装配——bootstrap 还没跑完或装配失败。
 *  前端应延后重试或提示用户重启应用。
 */
{ code: "FACADE_UNAVAILABLE" } | 
/**
 *  keyslot / KEK 删除失败。前端应展示通用错误并保留 UnlockPage 状态
 *  (用户至少还能继续尝试输口令);不应跳回 SetupPage——因为残留的
 *  keyslot 会让随后的 init 立即撞 AlreadyInitialized。
 */
{ code: "KEY_MATERIAL_WIPE_FAILED"; message: string } | 
/**
 *  key material 已清但 setup_status 没清。UI 现在处于过渡态:keyslot
 *  已无、setup_status 仍说 completed。最稳的引导是让用户重启应用。
 */
{ code: "STORAGE_FAILED"; message: string } | 
/**  兜底:其他非预期失败。 */
{ code: "INTERNAL"; message: string };

/**
 *  重置成功后返回的占位元数据。当前无字段——保留为对象以便未来扩展
 *  (比如下一步推荐操作的提示),而不必改 wire 形状。
 */
export type FactoryResetResult = Record<string, never>;

/**  `list_mobile_lan_interfaces` 单条结果。 */
export type LanInterfaceView = {
	name: string,
	ipv4: string,
};

/**
 *  `list_mobile_devices` 单条结果。来自 `MobileDeviceSummary`，不含
 *  password_hash；username 透传给前端作为辅助识别字段。
 */
export type MobileDeviceView = {
	deviceId: string,
	label: string,
	clientType: string,
	username: string,
	createdAtMs: number,
	lastSeenAtMs: number | null,
	lastSeenIp: string | null,
	reportedName: string | null,
	reportedOs: string | null,
};

/**
 *  前端直接 `error.code` switch 的 typed 错误。
 * 
 *  序列化形态：`{"code": "USERNAME_TAKEN", "username": "..."}`。
 *  不复用 `commands::error::CommandError`（那个用了 `tag = "code", content =
 *  "message"` 只能带单一字符串负载），mobile_sync 校验错误需要 `min` /
 *  `max` / `username` / `reason` 等结构化字段。
 */
export type MobileSyncError = { code: "FACADE_UNAVAILABLE" } | { code: "LABEL_EMPTY" } | { code: "LABEL_TOO_LONG"; max: number } | { code: "LAN_LISTENER_DISABLED" } | { code: "USERNAME_TAKEN"; username: string } | { code: "USERNAME_INVALID_SHAPE"; reason: string } | { code: "PASSWORD_TOO_SHORT"; min: number } | { code: "PASSWORD_TOO_LONG"; max: number } | { code: "PASSWORD_HASH_FAILED"; message: string } | { code: "DEVICE_NOT_FOUND"; deviceId: string } | { code: "INVALID_LAN_PARAMETER"; reason: string } | { code: "SETTINGS_LOAD_FAILED"; message: string } | { code: "SETTINGS_SAVE_FAILED"; message: string } | { code: "ENDPOINT_INFO_FAILED"; message: string } | { code: "LAN_PROBE_FAILED"; message: string } | { code: "NO_LAN_INTERFACE_AVAILABLE" } | { code: "PERSISTENCE_FAILED"; message: string } | { code: "QR_RENDER_FAILED"; message: string };

/**  `get_mobile_sync_settings` 返回值。 */
export type MobileSyncSettingsViewDto = {
	enabled: boolean,
	lanListenEnabled: boolean,
	lanAdvertiseIp: string | null,
	lanPort: number | null,
	/**
	 *  daemon 端 LAN listener 的 bind 失败原因(端口占用 / IP 不存在 / 权限)。
	 *  `Some` 表示 daemon 真的尝试过 bind 但失败,前端据此显示具体错误。
	 *  监听 URL 不再透出 —— 前端从 `lanAdvertiseIp` + `lanPort` 自行拼接。
	 */
	lanListenerError: string | null,
	shortcutInstallMethods: ShortcutInstallMethodView[],
};

/**  `register_mobile_device` 入参。 */
