export type ShortcutKeyDto = string | string[];

export type TraceMetadata = {
	trace_id: string,
	timestamp: number,
};

export type TrySilentUnlockError = 
/**  app facade 尚未装配。 */
{ code: "FACADE_UNAVAILABLE" } | 
/**
 *  keyring 中 KEK 与磁盘 keyslot 漂移 / 损坏 / 其他非预期错误。
 *  前端应弹出 "Unlock space" modal 收集明文口令,走
 *  [`unlock_space_with_passphrase`] 兜底。
 */
{ code: "INTERNAL"; message: string };

export type TrySilentUnlockResult = {
	/**
	 *  `true` = keyring 命中 + unwrap 成功,session 已 ready;
	 *  `false` = "没什么可恢复的"(还没 setup / setup 完但 keyslot 缺失);
	 *  注意 keyring 与 keyslot **漂移**会走 `Err` 而不是 `Ok(false)`,
	 *  前端据此区分"该弹解锁 modal" vs "该走 init/join 引导"。
	 */
	resumed: boolean,
};

/**
 *  前端 modal 提交的解锁请求。
 * 
 *  `passphrase` 在 Tauri IPC 边界以明文存在,**绝不**应当再往 HTTP/TCP
 *  上序列化(那等于送到本机 socket 上,违反 §安全)——这一边界仅止于
 *  同进程内 invoke handler。
 */
export type UnlockSpaceArgs = {
	passphrase: string,
};

/**
 *  前端可 `error.code` switch 的 typed 错误。序列化形态:
 *  `{"code": "WRONG_PASSPHRASE"}` / `{"code": "INTERNAL", "message": "..."}`。
 */
export type UnlockSpaceCommandError = 
/**
 *  space_setup facade 尚未装配——bootstrap 还没跑完或装配失败。
 *  前端应延后重试或提示用户重启应用。
 */
{ code: "FACADE_UNAVAILABLE" } | 
/**  没有 setup 过——前端应引导走 init / join 流程,而不是 unlock。 */
{ code: "SETUP_NOT_COMPLETED" } | 
/**
 *  `setup_status.has_completed=true` 但磁盘 keyslot 缺失。
 *  前端应引导 factory reset。
 */
{ code: "SPACE_NOT_INITIALIZED" } | 
/**
 *  口令不能 unwrap 已存 master key。前端应在 modal 中提示
 *  "口令错误,请重试",**不关闭** modal。
 */
{ code: "WRONG_PASSPHRASE" } | 
/**
 *  keyslot 文件存在但版本不支持 / 反序列化失败。再正确的口令也
 *  派生不出能解开的 KEK。前端应引导 factory reset 或重新 join。
 */
{ code: "CORRUPTED_KEY_MATERIAL" } | 
/**
 *  兜底:IO / 序列化 / migration resume 等非预期失败。`message`
 *  仅面向开发者日志,前端展示通用错误对话框 + Sentry 上报即可。
 */
{ code: "INTERNAL"; message: string };

/**  解锁成功后返回的最小元数据。 */
export type UnlockSpaceResultDto = {
	spaceId: string,
};

export type UpdateKeyboardShortcutsResult = {
	keyboardShortcuts: { [key in string]: ShortcutKeyDto },
};

/**  Metadata returned to the frontend when an update is available. */
export type UpdateMetadata = {
	version: string,
	currentVersion: string,
	body: string | null,
	date: string | null,
};

/**
 *  `update_mobile_sync_settings` 入参 patch。
 * 
 *  `lanAdvertiseIp` / `lanPort` 是三态：字段缺失=不动；显式 null=清空；给值=写入。
 *  前端用 `JSON.stringify` 时 `undefined` 字段被 drop（缺失），`null` 显式
 *  序列化（→ `Some(None)`），有值（→ `Some(Some(value))`）。
 */
export type UpdateMobileSyncSettingsArgs = UpdateMobileSyncSettingsArgs_Serialize | UpdateMobileSyncSettingsArgs_Deserialize;

/**
 *  `update_mobile_sync_settings` 入参 patch。
 * 
 *  `lanAdvertiseIp` / `lanPort` 是三态：字段缺失=不动；显式 null=清空；给值=写入。
 *  前端用 `JSON.stringify` 时 `undefined` 字段被 drop（缺失），`null` 显式
 *  序列化（→ `Some(None)`），有值（→ `Some(Some(value))`）。
 */
export type UpdateMobileSyncSettingsArgs_Deserialize = {
	enabled?: boolean | null,
	lanListenEnabled?: boolean | null,
	lanAdvertiseIp?: string | null,
	lanPort?: number | null,
};

/**
 *  `update_mobile_sync_settings` 入参 patch。
 * 
 *  `lanAdvertiseIp` / `lanPort` 是三态：字段缺失=不动；显式 null=清空；给值=写入。
 *  前端用 `JSON.stringify` 时 `undefined` 字段被 drop（缺失），`null` 显式
 *  序列化（→ `Some(None)`），有值（→ `Some(Some(value))`）。
 */
export type UpdateMobileSyncSettingsArgs_Serialize = {
	enabled: boolean | null,
	lanListenEnabled: boolean | null,
	lanAdvertiseIp: string | null,
	lanPort: number | null,
};

export type UpdateMobileSyncSettingsResult = {
	enabled: boolean,
	lanListenEnabled: boolean,
	lanAdvertiseIp: string | null,
	lanPort: number | null,
	/**
	 *  Wire-兼容历史字段。daemon 装入 LAN lifecycle controller 时
	 *  (GUI 路径) settings 改动即时生效, 本字段永远为 false; CLI fallback
	 *  装配仍按"任一字段实际变化 → true / 同值 → false"返回, 表达
	 *  "下一次 daemon 重启才生效"的旧语义。前端按本字段决定是否弹
	 *  restart 横幅, true → 弹, false → 即时反馈即可。
	 */
	restartRequired: boolean,
	/**
	 *  即时生效路径下 LAN listener bind 失败的原因。
	 * 
	 *  写盘成功但 adapter `apply(target)` 后端口没起来时(端口占用、权限
	 *  不足、IP 不可分配等),facade 从 `MobileSyncEndpointInfoPort` 读出
	 *  `BindFailed{reason}` 并透传到此字段。前端引导对话框据此在 happy
	 *  path 流程中提前 toast.error 并阻断下一步, 避免用户填完 label 才
	 *  发现 iPhone 连不上。CLI fallback / 无 lifecycle 装配下永远为 None。
	 */
	lanListenerBindError: string | null,
};

/* Tauri Specta runtime */
async function typedError<T, E>(result: Promise<T>): Promise<{ status: "ok"; data: T } | { status: "error"; error: E }> {
    try {
        return { status: "ok", data: await result };
    } catch (e) {
        if (e instanceof Error) throw e;
        return { status: "error", error: e as any };
    }
}

type EventEmit<T> = [T] extends [null] ? () => Promise<void> : (payload: T) => Promise<void>;

function makeEvent<T>(name: string, serialize?: (payload: T) => unknown, deserialize?: (payload: any) => T) {
    const mapEvent = (cb: __TAURI_EVENT.EventCallback<T>) => (event: __TAURI_EVENT.Event<any>) => cb({ ...event, payload: deserialize ? deserialize(event.payload) : event.payload });
    const mapPayload = (payload: T) => serialize ? serialize(payload) : payload;

    const base = {
        listen: (cb: __TAURI_EVENT.EventCallback<T>) => __TAURI_EVENT.listen(name, mapEvent(cb)),
        once: (cb: __TAURI_EVENT.EventCallback<T>) => __TAURI_EVENT.once(name, mapEvent(cb)),
        emit: ((payload: T) => __TAURI_EVENT.emit(name, mapPayload(payload)) as unknown) as EventEmit<T>
    };

    const fn = (target: import("@tauri-apps/api/webview").Webview | import("@tauri-apps/api/window").Window) => ({
        listen: (cb: __TAURI_EVENT.EventCallback<T>) => target.listen(name, mapEvent(cb)),
        once: (cb: __TAURI_EVENT.EventCallback<T>) => target.once(name, mapEvent(cb)),
        emit: ((payload: T) => target.emit(name, mapPayload(payload)) as unknown) as EventEmit<T>
    });

    return Object.assign(fn, base);
}

